import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe('pull', () => {
  it('should handle through streams (objects with sink and source) correctly without treating functions as objects', () => {
    // Create a simple through stream object
    const results: number[] = [];
    let sinkFn: Function;

    const through = {
      sink: (read: Function) => { sinkFn = read; },
      source: (end: any, cb: Function) => { sinkFn(end, cb); }
    };

    const source = (end: any, cb: Function) => cb(null, 42);
    const sink = (read: Function) => read(null, (end: any, data: any) => { if (!end) results.push(data); });

    pull(source, through, sink);
    expect(results).toEqual([42]);
  });
});
```

